import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { AuthService } from '../../core/services/auth.service';
import { Invoice } from '../../core/models';

/**
 * Invoice detail: line breakdown + Pay button (open → paid) and a link to the
 * printable view. service_agent wires getInvoice / payInvoice.
 */
@Component({
  selector: 'app-invoice-detail',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './invoice-detail.component.html',
  styleUrl: './invoice-detail.component.css',
})
export class InvoiceDetailComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);
  readonly working = signal(false);
  id = '';

  readonly invoice = signal<Invoice>({
    id: 'inv1',
    salesOrderId: 'so4',
    status: 'open',
    issuedAt: '2026-07-10T00:00:00Z',
    paidAt: null,
    customer: { id: 'c1', name: 'Northwind Traders', email: 'orders@northwind.example' },
    lines: [
      { id: 'il1', invoiceId: 'inv1', productId: 'p1', description: 'Widget', qty: 30, unitPriceCents: 999 },
    ],
    totalCents: 29970,
  });

  readonly canPay = computed(() => this.auth.isSales());
  readonly totalCents = computed(() =>
    (this.invoice().lines ?? []).reduce((s, l) => s + l.qty * l.unitPriceCents, 0),
  );

  constructor(public auth: AuthService, private route: ActivatedRoute) {}

  ngOnInit(): void {
    this.id = this.route.snapshot.paramMap.get('id') ?? '';
    // service_agent: this.invoice.set(await ApiService.getInvoice(this.id)).
  }

  money(cents: number): string {
    return (cents / 100).toLocaleString(undefined, { style: 'currency', currency: 'USD' });
  }

  pay(): void {
    this.working.set(true);
    // service_agent: ApiService.payInvoice(this.id).
    this.invoice.update((i) => ({ ...i, status: 'paid', paidAt: '2026-07-12T00:00:00Z' }));
    this.working.set(false);
  }
}
